-- ================================================================
-- MIGRAR DATOS DE PRODUCTOS - Estructura antigua → nueva
-- ================================================================
-- Origen: codigoProveedor, id_proveedor, deposito, esCombo
-- Destino: id_proveedor, stock2 (←deposito), stock3, es_combo, activo
-- ================================================================
-- ⚠️  Ejecutar DESPUÉS de recrear-productos-exacto.sql (tabla vacía)
--    O en tabla ya creada con la nueva estructura
-- ⚠️  Duplicados (id=0, mismo codigo): se inserta solo 1 por codigo
-- ⚠️  Producto id=0 CPMC: se asigna id siguiente disponible
-- ================================================================

SET SQL_MODE = "NO_AUTO_VALUE_ON_ZERO";
SET FOREIGN_KEY_CHECKS = 0;

-- Deshabilitar triggers temporalmente para inserción masiva
DROP TRIGGER IF EXISTS `prod_insertar`;

-- ================================================================
-- INSERT con mapeo de columnas:
-- deposito → stock2 (NULL→0.00)
-- stock3 → 0.00 (no existía)
-- codigoProveedor, esCombo → omitidos
-- id_proveedor se mantiene
-- activo → 1
-- es_combo → 0 (esCombo era legacy)
-- ================================================================

